const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
readline.question('', (n) => {
    let sum = 0;
    while (n > 0) {
        sum += n % 10;
        n = Math.floor(n / 10);
    }
    console.log(sum);
    readline.close();
});

